Sure! Here's an example of a Discord bot using Discord.js v14 with a single slash command, `/ban`. This example assumes that you have already set up a bot on the Discord developer portal and have invited it to your server.

First, you will need to install the Discord.js library and its dependencies. You can do this by running the following command in your terminal:

```
npm install discord.js @discordjs/builders @discordjs/rest
```

Next, you can create a new file for your bot, such as `index.js`, and add the following code:

```javascript
const { Client, Collection, GatewayIntentBits } = require('discord.js');
const { REST } = require('@discordjs/rest');
const { Routes } = require('discord-api-types/v10');

// Create a new client instance
const client = new Client({ intents: [GatewayIntentBits.Guilds, GatewayIntentBits.GuildMembers] });

// Create a new collection to store commands
client.commands = new Collection();

// Add the /ban command to the collection
client.commands.set('ban', {
  data: new SlashCommandBuilder()
    .setName('ban')
    .setDescription('Ban a user from the server')
    .addUserOption(option =>
      option.setName('user')
        .setDescription('The user to ban')
        .setRequired(true))
    .addStringOption(option =>
      option.setName('reason')
        .setDescription('The reason for the ban')),
  async execute(interaction) {
    // Check if the user has the necessary permissions
    if (!interaction.member.permissions.has('BAN_MEMBERS')) {
      return interaction.reply({ content: 'You do not have permission to ban members.', ephemeral: true });
    }

    // Get the user to ban and the reason for the ban
    const user = interaction.options.getUser('user');
    const reason = interaction.options.getString('reason') || 'No reason provided';

    // Ban the user
    try {
      await interaction.guild.members.ban(user, { reason });
      interaction.reply({ content: `User ${user.tag} has been banned.`, ephemeral: true });
    } catch (error) {
      interaction.reply({ content: `Failed to ban user ${user.tag}.`, ephemeral: true });
    }
  },
});

// Create a new REST instance
const rest = new REST({ version: '10' }).setToken('your-bot-token-goes-here');

// Register the /ban command with the Discord API
rest.put(Routes.applicationGuildCommands(client.application.id, 'your-guild-id-goes-here'), { body: client.commands.map(command => command.data.toJSON()) })
  .then(() => console.log('Successfully registered /ban command.'))
  .catch(console.error);

// Log in the client
client.login('your-bot-token-goes-here');
```

Make sure to replace `'your-bot-token-goes-here'` and `'your-guild-id-goes-here'` with your actual bot token and guild ID.

