First, let's define a helper function to convert markdown headers to HTML headers:
```c++
std::string toHtmlHeader(const std::string& markdown, int level) {
  // Markdown headers start with one to six '#' characters,
  // followed by the header text.
  // For example, "# Header 1", "## Header 2", etc.
  size_t pos = markdown.find("#");
  if (pos == std::string::npos || pos + level > markdown.size()) {
    return "";
  }
  std::string headerText = markdown.substr(pos + level);
  // Remove any trailing '#' characters from the header text
  headerText.erase(headerText.find_last_not_of('#') + 1);
  // Convert the header to HTML
  return "<h" + std::to_string(level) + ">" + headerText + "</h" + std::to_string(level) + ">";
}
```
Now we can define the main function to convert markdown to HTML:
```c++
#include <string>
#include <vector>
#include <regex>

std::string markdownToHtml(std::string& markdown) {
  // Replace newlines with HTML line breaks
  std::replace(markdown.begin(), markdown.end(), '\n', "<br>");

  // Handle markdown headers
  std::regex headerRegex("(^#{1,6}\\s+)(.+)$", std::regex::multiline);
  std::smatch headerMatch;
  while (std::regex_search(markdown, headerMatch, headerRegex)) {
    int level = headerMatch[1].str().size() / 2;
    std::string headerText = headerMatch[2].str();
    std::string htmlHeader = toHtmlHeader(headerText, level);
    markdown.replace(headerMatch.position(), headerMatch.length(), htmlHeader);
  }

  // Handle markdown bold text
  std::regex boldRegex("\\*\\*(.+)\\*\\*", std::regex::icase);
  std::smatch boldMatch;
  while (std::regex_search(markdown, boldMatch, boldRegex)) {
    std::string boldText = boldMatch[1].str();
    std::string htmlBold = "<strong>" + boldText + "</strong>";
    markdown.replace(boldMatch.position(), boldMatch.length(), htmlBold);
  }

  // Handle markdown italic text
  std::regex italicRegex("\\*(.+)\\*", std::regex::icase);
  std::smatch italicMatch;
  while (std::regex_search(markdown, italicMatch, italicRegex)) {
    std::string italicText = italicMatch[1].str();
    std::string htmlItalic = "<em>" + italicText + "</em>";
    markdown.replace(italicMatch.position(), italicMatch.length(), htmlItalic);
  }

  // Handle markdown lists
  std::regex listRegex("(^[*+-]\\s+)(.+)$", std::regex::multiline);
  std::smatch listMatch;
  while (std::regex_search(markdown, listMatch, listRegex)) {
    std::string listItem = listMatch[2].str();
    std::string htmlListItem = "<li>" + listItem + "</li>";
    markdown.replace(listMatch.position(), listMatch.length(), htmlListItem);
  }

  // Wrap the entire markdown text in an HTML paragraph tag
  std::string html = "<p>" + markdown + "</p>";

  // Remove any leading or trailing newlines
  html.erase(html.begin(), std::find_if(html.begin(), html.end(), [](unsigned char ch) {
    return !std::isspace(ch);
  }));
  html.erase(std::find_if(html.rbegin(), html.rend(), [](unsigned char ch) {
    return !std::isspace(ch);
  }).base(), html.end());

  return html;
}
```
This `markdownToHtml` function works by searching the input markdown text for various patterns (headers, bold text, etc.) and replacing them with the corresponding HTML tags. The function uses regular expressions to find these patterns. For example, the regular expression `"(^#{1,6}\\s+)(.+)$"` matches headers that start with one to six '#' characters, followed by whitespace, followed by the header text.

The function also includes a helper function `toHtmlHeader` that converts a markdown header to an HTML header. This function takes a markdown header string and the header level as arguments, and returns the corresponding HTML header string.

After all the markdown patterns have been replaced with HTML tags, the function wraps the entire input text in an HTML paragraph tag (`<p>`). Finally, the function removes any leading or trailing newlines from the output HTML string.

Note that this `markdownToHtml` function only handles a small subset of markdown features. If you need to handle more features, you will need to modify the function accordingly. For example, you could add support for links, images, code blocks, and other common markdown features. However, for simple markdown text, this function should be sufficient.

